fn main() {
    let mut head = Some(Box::new(Node { value: 1 });
    head.as_mut().unwrap().next = Some(Box::new(Node { value: 2 });
    head.as_mut().unwrap().next.as_mut().unwrap().next = Some(Box::new(Node { value: 3 }));

    let current = &mut head;
    while let Some(node) = current {
